using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ─── Configuration ───────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ─── Build chat client with automatic function invocation ────────
var innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient();

IChatClient client = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

// ─── Register tools ──────────────────────────────────────────────
var tools = new ResearchTools();
var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]
};

// ─── Get research topic from the user ────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}");
Console.WriteLine(new string('─', 50));

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic, you must:
        1. Search the web with several distinct queries to gather broad information.
        2. Save the most important findings as notes using the SaveNote tool.
        3. Once you have gathered enough information (at least 2-3 searches),
           retrieve your notes with GetNotes, then write a comprehensive summary.

        Structure your final summary with:
        - An overview paragraph
        - Key findings (bulleted)
        - A brief conclusion

        Be factual and cite specifics from your research where possible.
        """),
    new(ChatRole.User,
        $"Please research the following topic and provide a comprehensive summary:\n\n{topic}")
};

// ─── Run the agent ───────────────────────────────────────────────
var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine();
Console.WriteLine(new string('═', 50));
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine(new string('═', 50));
Console.WriteLine(response.Text);

// ─── Tool Definitions ───────────────────────────────────────────

sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http;

    public ResearchTools()
    {
        _http = new HttpClient();
        _http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
    }

    [Description("Search the web for information on a topic. Returns relevant snippets from search results.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"\n  🌐 Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await _http.GetStringAsync(url);

            var results = new List<string>();

            // Try to extract title + snippet pairs
            var blocks = Regex.Matches(html,
                @"class=""result__a""[^>]*>(?<title>.*?)</a>.*?class=""result__snippet""[^>]*>(?<snippet>.*?)</",
                RegexOptions.Singleline);

            foreach (Match match in blocks.Take(5))
            {
                var title = StripHtml(match.Groups["title"].Value);
                var snippet = StripHtml(match.Groups["snippet"].Value);
                if (!string.IsNullOrWhiteSpace(snippet))
                    results.Add($"**{title}**: {snippet}");
            }

            // Fallback: extract snippets only
            if (results.Count == 0)
            {
                var snippets = Regex.Matches(html,
                    @"class=""result__snippet""[^>]*>(.*?)</",
                    RegexOptions.Singleline);
                foreach (Match m in snippets.Take(5))
                {
                    var text = StripHtml(m.Groups[1].Value);
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add(text);
                }
            }

            Console.WriteLine($"    Found {results.Count} result(s).");
            return results.Count > 0
                ? string.Join("\n\n", results.Select((r, i) => $"[{i + 1}] {r}"))
                : "No results found. Try rephrasing your query.";
        }
        catch (Exception ex)
        {
            Console.WriteLine($"    ⚠️  Search error: {ex.Message}");
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save an important research finding as a note for later reference.")]
    public string SaveNote(
        [Description("The content of the note to save")] string content)
    {
        _notes.Add(content);
        Console.WriteLine($"  📝 Saved note #{_notes.Count}");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes to review before writing a summary.")]
    public string GetNotes()
    {
        Console.WriteLine($"  📖 Retrieving {_notes.Count} saved note(s)");
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1} ---");
            sb.AppendLine(_notes[i]);
            sb.AppendLine();
        }
        return sb.ToString();
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, "<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        return Regex.Replace(text, @"\s+", " ").Trim();
    }
}

